async function e(e,t,n){if(!Number.isFinite(e)||e<-90||e>90||!Number.isFinite(t)||t<-180||t>180)throw Error(`Coordenadas inválidas.`);let r=new URL(`https://api.open-meteo.com/v1/forecast`);r.search=new URLSearchParams({latitude:String(e),longitude:String(t),daily:`weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,precipitation_probability_max,wind_gusts_10m_max,et0_fao_evapotranspiration`,timezone:`auto`,forecast_days:`7`}).toString();let i=await fetch(r,{signal:n});if(!i.ok)throw Error(`Serviço meteorológico indisponível (${i.status}).`);let a=await i.json();if(!a.daily?.time?.length)throw Error(`A previsão não devolveu dados diários.`);return{latitude:a.latitude,longitude:a.longitude,timezone:a.timezone,generatedAt:new Date().toISOString(),source:`Open-Meteo`,days:a.daily.time.map((e,t)=>({date:e,weatherCode:a.daily.weather_code[t]??0,temperatureMax:a.daily.temperature_2m_max[t]??0,temperatureMin:a.daily.temperature_2m_min[t]??0,precipitationMm:a.daily.precipitation_sum[t]??0,precipitationProbability:a.daily.precipitation_probability_max[t]??0,windGustKmh:a.daily.wind_gusts_10m_max[t]??0,evapotranspirationMm:a.daily.et0_fao_evapotranspiration[t]??0}))}}export{e as t};